require "config.JobConfig"
require "config.JobPondConfig"
require "config.Define"
require "manager.JobPoolManager"

GameJobPond = class()

function GameJobPond:ctor(player)
    self.userId = player.userId
    self.refreshPrice = 0
    self.curJobsPond = {}
end

function GameJobPond:init()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    self:randomAllJobs(player)
end

--得到奖池里面的所有的职业
function GameJobPond:randAllJobByJobPond(player, pool)
    player.Jobs_Pond = {}
    local poolIds = StringUtil.split(pool.poolId, "#")
    local amounts = StringUtil.split(pool.amount, "#")
    for i = 1, #poolIds do
        local Jobs = JobPoolManager:randomJob(tonumber(poolIds[i]), tonumber(amounts[i]))
        for _, job in pairs(Jobs) do
            local config = JobConfig:getJobById(job.id)
            if config ~= nil then
                table.insert(player.Jobs_Pond, config)
            end
        end
        i = i + 1
    end
end

--随机奖池的所有职业
function GameJobPond:randomAllJobs(player)
    local pool = JobPondConfig:randomJobPond()
    local price = pool.price
    player.lastJobs_PondId = pool.id
    self:randAllJobByJobPond(player, pool)
    local jobData = {}
    for id, job in pairs(player.Jobs_Pond) do
        table.insert(jobData, {
            id = tonumber(job.id),
            isOpen = job.isOpen
        })
    end
    if player.pondRefreshTimes <= #GameConfig.pondRefreshPrice then
        self.refreshPrice = tonumber(GameConfig.pondRefreshPrice[player.pondRefreshTimes])
    else
        self.refreshPrice = tonumber(GameConfig.pondRefreshPrice[#GameConfig.pondRefreshPrice])
    end
    local params = {
        refreshPrice = self.refreshPrice,
        price = price,
        allJobs = jobData
    }
    player.pondRefreshTimes = player.pondRefreshTimes + 1
    GamePacketSender:sendJobsUpdateData(player.rakssid, json.encode(params))
end

--当玩家抽取职业(付钱成功后)
function GameJobPond:onPlayerExtractJob(player)
    local jobId = self:randomJobIdByCurJobsPond(player)
    player.GameJob:updateJobUIData(jobId, 1)

    for _, v in pairs(player.Jobs_Pond) do
        if v.id == jobId then
            v.isOpen = true
        end
    end
    GamePacketSender:sendSynJobsIdData(player.rakssid, jobId)
    return true
end

--从当前奖池随机出一个职业
function GameJobPond:randomJobIdByCurJobsPond(player)
    local jobId = 0
    local weight = 0
    local weightSum = 0
    for pos, item in pairs(player.Jobs_Pond) do
        weightSum = weightSum + item.weight2
    end
    local random = math.random(1, weightSum)
    for pos, item in pairs(player.Jobs_Pond) do
        weight = weight + item.weight2
        if weight >= random then
            jobId = item.id
            weightSum = weightSum - item.weight2
            table.remove(player.Jobs_Pond, pos)
            break
        end
    end
    return jobId
end

return GameJobPond